```plantuml
@startuml
class TilePyramid {
}

class TiledGriddedCoverage {
  id: Integer
  dataType = tiles
  coverageDataType: TGCEDatatype
  scale: Real
  offset: Real
  precision: Real?
  nullValue: Real?
  gridCellEncoding: GridCellEncoding?
  unitOfMeasure: String?
  fieldName: String?
  quantityDefinition: String?
}

class CoverageTile {
  scale: Real
  offset: Real
  min: Real?
  max: Real?
  mean: Real?
  standardDeviation: Real?
}

class Tile {
}

class TGCEDatatype <<enumeration>> {
  integer
  float
}

class GridCellEncoding <<enumeration>> {
  grid-value-is-center
  grid-value-is-area
  grid-value-is-corner
}

TilePyramid <|-- TiledGriddedCoverage
TilePyramid o-- "*" Tile
TiledGriddedCoverage o-- "*" CoverageTile
Tile <|-- CoverageTile

@enduml
```
